1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const withFirstInsurance = (base: number): number =>
18	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
19	
20	const groupBase = (type: string, count: number): number => {
21	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
22	    return withFirstInsurance(BLOCK_BASE_PREMIUM);
23	  }
24	  return count * withFirstInsurance(BASE_PREMIUM[type]);
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const DEDUCTIBLE = 100;
37	
38	export const runScenario = (input: any): { results: unknown[] } => {
39	  const results: unknown[] = [];
40	  const policies: { items: any[]; cap: number; remainingCap: number }[] = [];
41	  for (let stepIndex = 0; stepIndex < input.steps.length; stepIndex++) {
42	    const step = input.steps[stepIndex];
43	    if (step.op === "claim") {
44	      const policy = policies[step.policy];
45	      let totalPayout = 0;
46	      for (const damage of step.incident.damages) {
47	        const payout = Math.max(0, damage.amount - DEDUCTIBLE);
48	        totalPayout += payout;
49	      }
50	      const cappedPayout = Math.min(totalPayout, policy.remainingCap);
51	      policy.remainingCap -= cappedPayout;
52	      results.push({ payout: Math.floor(cappedPayout), remainingCap: policy.remainingCap });
53	      continue;
54	    }
55	    const items: { type: string; cursed?: boolean }[] = step.items;
56	    const countsByType = new Map<string, number>();
57	    for (const item of items) {
58	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
59	    }
60	    let premium = PROCESSING_FEE;
61	    let policyBase = 0;
62	    for (const [type, count] of countsByType) {
63	      premium += groupBase(type, count);
64	      policyBase += count * BASE_PREMIUM[type];
65	    }
66	    if (input.customer?.yearsWithMHPCO >= 2) {
67	      premium -= 0.2 * policyBase;
68	    }
69	    if (stepIndex >= 1) {
70	      premium -= 0.15 * policyBase;
71	    }
72	    for (const item of items) {
73	      if (item.cursed) {
74	        premium += 0.5 * BASE_PREMIUM[item.type];
75	      }
76	      if ((item as any).enchantment >= 5) {
77	        premium += 0.3 * BASE_PREMIUM[item.type];
78	      }
79	    }
80	    let insuranceSum = 0;
81	    for (const item of items) {
82	      insuranceSum += INSURANCE_VALUE[item.type];
83	    }
84	    const cap = 2 * insuranceSum;
85	    policies.push({ items, cap, remainingCap: cap });
86	    results.push({ premium: Math.ceil(premium) });
87	  }
88	  return { results };
89	};
